arguments.new_str:
protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // [Breaking] HasIndex throws at startup in EF Core 9 Cosmos provider.
    // Manage indexing via Azure Portal, Bicep, or Terraform instead.
    // modelBuilder.Entity<Product>().HasIndex(p => p.Sku);

    modelBuilder.Entity<Product>(b =>
    {
        b.ToContainer("Products");

        // [Breaking] EF Core 9 renamed default discriminator from "Discriminator" to "$type".
        // Preserve "Discriminator" so existing 500K documents remain queryable and
        // direct SQL queries (c.Discriminator) continue to work.
        b.HasDiscriminator<string>("Discriminator");

        // [Breaking] EF Core 9 no longer embeds the discriminator in the JSON id.
        // EF8 wrote ids as "Product|123"; EF9 defaults to just "123".
        // Preserve the old format so FindAsync/point-reads find existing documents.
        b.HasRootDiscriminatorInJsonId(true);
    });
}

arguments.old_str:
class CosmosQuery
{
    void FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";
        // Also uses sync APIs
        var products = ctx.Products.Where(p => p.Sku == "ABC").ToList();
    }
}

arguments.new_str:
class CosmosQuery
{
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — safe: we preserved "Discriminator" as the discriminator
        // property name in OnModelCreating, so c.Discriminator still works.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // [Breaking] EF Core 9 Cosmos provider no longer supports sync I/O.
        // ToList() throws; use ToListAsync() instead.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

